SELECT log_id, tool_name, server_name, version, user_id, username, dept_id, tenant_id, status, cost_millis, error_message, create_time FROM ai_mcp_tool_audit_log
AND tool_name LIKE CONCAT('%', #{toolName}, '%')
AND status = #{status}
AND tenant_id = #{tenantId}
ORDER BY create_time DESC, log_id DESC
